const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
if (input.length === 0) process.exit(0);
let idx = 0;
const T = parseInt(input[idx++], 10);
const holes = {A:1,B:2,D:1,O:1,P:1,Q:1,R:1};
let results = [];
for (let t = 0; t < T; ++t) {
  const s = input[idx++];
  let total = 0;
  for (let i = 0; i < s.length; ++i) {
    total += holes[s[i]] || 0;
  }
  results.push(String(total));
}
console.log(results.join('\n'));
